const estudiante = $('Buscar Estudiante (Postgres)').item.json;
const cert = $json;

// cert.fecha es una columna DATE pura (sin hora ni zona horaria): se formatea
// leyendo directamente los componentes YYYY-MM-DD del string, sin pasar por
// un objeto Date/Intl (evita que una conversión de zona horaria le reste un
// día, ya que una fecha sin hora no tiene un instante real que convertir).
const MESES = ['enero', 'febrero', 'marzo', 'abril', 'mayo', 'junio', 'julio', 'agosto', 'septiembre', 'octubre', 'noviembre', 'diciembre'];
const fechaStr = typeof cert.fecha === 'string' ? cert.fecha : cert.fecha.toISOString();
const [anio, mes, dia] = fechaStr.slice(0, 10).split('-').map(Number);
const fechaEmision = `${String(dia).padStart(2, '0')} de ${MESES[mes - 1]} de ${anio}`;
const urlVerificacion = `https://verificacion.tudominio.edu.ec/certificados/${cert.codigoUnico}`;

return [{
  json: {
    codigoUnico: cert.codigoUnico,
    cedula: estudiante.cedula,
    nombreCompleto: estudiante.nombres,
    carrera: estudiante.carrera,
    nivel: estudiante.nivel,
    periodoActual: estudiante.periodoActual,
    modalidad: estudiante.modalidad,
    fechaEmision,
    urlVerificacion
  }
}];

